model.metadata:
CREATE VIEW v_c3_penduduk_01 AS
  SELECT nikx, nama
  FROM bansos_db.master_penduduk;

CREATE VIEW v_c3_penduduk_02 AS
  SELECT tanggal_lahirr, nik
  FROM bansos_db.master_penduduk;

CREATE VIEW v_c3_edge_nix AS
  SELECT nix, nama
  FROM bansos_db.master_penduduk;

CREATE VIEW v_c3_eligibility_01 AS
  SELECT status_eligble, nik
  FROM bansos_db.eligibility;

CREATE VIEW v_c3_eligibility_02 AS
  SELECT programid, nik
  FROM bansos_db.eligibility;

CREATE VIEW v_c3_program_01 AS
  SELECT nama_progam, program_id
  FROM bansos_db.master_program_bansos;

CREATE VIEW v_c3_program_02 AS
  SELECT nomnal, program_id
  FROM bansos_db.master_program_bansos;

CREATE VIEW v_c3_penerima_01 AS
  SELECT penerimaid, nik
  FROM bansos_db.master_penerima;

CREATE VIEW v_c3_penerima_02 AS
  SELECT nikk, penerima_id
  FROM bansos_db.master_penerima;

CREATE VIEW v_c3_keluarga_01 AS
  SELECT no_kkk, alamat
  FROM bansos_db.master_keluarga;

CREATE VIEW v_c3_keluarga_02 AS
  SELECT wilaya_id, no_kk
  FROM bansos_db.master_keluarga;

CREATE VIEW v_c3_unknown_col AS
  SELECT qwerty_col, nik
  FROM bansos_db.master_penduduk;

CREATE VIEW v_c3_prd_tgl AS
  SELECT nik, tgl_lahir
  FROM bansos_db.master_penduduk;

CREATE VIEW v_c3_ok_penduduk AS
  SELECT nik, nama, tanggal_lahir, pekerjaan, penghasilan
  FROM bansos_db.master_penduduk;

CREATE VIEW v_c3_ok_eligibility AS
  SELECT eligibility_id, program_id, nik, status_eligible, validated_at, validated_by
  FROM bansos_db.eligibility;

CREATE VIEW v_c3_ok_program AS
  SELECT program_id, nama_program, nominal
  FROM bansos_db.master_program_bansos;

CREATE VIEW v_c3_ok_penerima AS
  SELECT penerima_id, nik, nama_penerima
  FROM bansos_db.master_penerima;

CREATE VIEW v_c3_ok_keluarga AS
  SELECT no_kk, wilayah_id, alamat
  FROM bansos_db.master_keluarga;
